import os
import json
import pika
from threading import Thread


class JobProcessor(Thread):
    def __init__(self, queue_name):
        super().__init__()

        self._connection = None
        self._channel = None

        self.queue_name = queue_name

    def on_response(self):
        while True:
            try:
                channel = pika.BlockingChannel(connection=self._connection)
                channel.start()

                channel.basic_consume(on_message_callback=self.process, auto_ack=True, consumer_tag='job')
                channel.run()

            except (Exception): pass

    def process(self, ch, method, props, body):
        job = json.loads(body)

        print('Job {name} started'.format(**job))

        try:
            print(os.system('sleep 3; echo Hello {message} from PID: ${pid}; date; df -h'.format(
                message=job['message'],
                pid=os.getpid())))

            ch.basic_ack(delivery_tag = method.delivery_tag)
        except Exception as ex:
            print('Job {name} failed: {error}'.format(**job, error=ex))

    def on_connection(self):
        print('Connection opened')

        self._connection = pika.BlockingConnection()
        self._channel = pika.BlockingChannel(connection=self._connection)

        self._channel.queue_declare(self.queue_name)

    def on_open(self, connection): pass
    def on_close(self): print('Connection closed')

    @staticmethod
    def start():
        queue_name = 'jobs' # this is hard coded in rabbitmq consumer
        processor = JobProcessor(queue_name=queue_name)

        processor.on_connection()
        processor.on_response()